    cmd = input("Enter command: ")
    if not cmd:
        return
    if any(c in cmd for c in [';', '|', '&', '<', '>', '(', ')', '{', '}', '$', '`', '"', "'", '\\']):
        print("Invalid command")
        return
    try:
        subprocess.run(cmd.split(), check=True)
    except subprocess.CalledProcessError as e:
        print(f"Error: {e}")

